import React from 'react'
import "../Css2/Contact2.css"
export const Contact2 = () => {
  return (
    <div className='contact2' id='Contact'>
        <div className='contact-name'>
            <p>Contact Me!</p>
        </div>
        <div className='contact-div'>
          <div className='contact-my'>
              <div>
                My Contact
              </div>
              <div>
                <ul className='my-contact'>
                  <li><span><img src="/Images/mail.png" alt="" /></span><span>abak00350@gmail.com</span></li>
                  <li><span><img src="/Images/call.png" alt="" /></span>+91 6370014498</li>
                  <li><span><img src="/Images/location.png" alt="" /></span>Cuttack,Odisha</li>
                  <li><span><img src="/Images/github.png" alt="" /></span><span><a href="621543">ajayahara</a></span></li>
                </ul>
              </div>
          </div>
          <div className='contact-form'>
            <form>
             <div>
             <label htmlFor="name">Name:</label>
              <input type="text" placeholder="Enter name"/>
             </div>
             <div>
             <label htmlFor="email">Email:</label>
              <input type="email" placeholder='Enter email' />
             </div>
             <div>
             <label htmlFor="mobile">Mobile:</label>
              <input type="number" placeholder='Enter mobile' />
             </div>
             <div>
             <label htmlFor="message">Message</label>
              <textarea name="message" placeholder='Enter message'></textarea>
             </div>
              <input type="submit" />
            </form>
          </div>
        </div>
    </div>
  )
}
